import{c as s,cG as a,cb as i,c8 as e,cf as n,cT as l,ce as t}from"./chunks/framework.BlkIsu1j.js";const p=JSON.parse('{"title":"实战工作流","description":"","frontmatter":{"title":"实战工作流","outline":"deep","layout":"doc","prev":"/ai/claudecode/04-ecosystem","next":"/ai/claudecode/06-mindset","date":"2026-05-20T10:00:00.000Z"},"headers":[],"relativePath":"ai/claudecode/05-workflows.md","filePath":"ai/claudecode/05-workflows.md","lastUpdated":1779211503000}'),r={id:"frontmatter-title",tabindex:"-1"};const h=s({name:"ai/claudecode/05-workflows.md"},[["render",function(s,p,h,d,o,g){return a(),i("div",null,[e("h1",r,[n(l(s.$frontmatter.title)+" ",1),p[0]||(p[0]=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),p[1]||(p[1]=t('<p>本章展示在实际项目开发中，Claude Code 如何介入各个阶段的工作流。</p><h2 id="_5-1-新功能开发流程" tabindex="-1">5.1 新功能开发流程 <a class="header-anchor" href="#_5-1-新功能开发流程" aria-label="Permalink to “5.1 新功能开发流程”">​</a></h2><p>这是最常见的场景：从零开始开发一个新功能。</p><h3 id="工作流概览" tabindex="-1">工作流概览 <a class="header-anchor" href="#工作流概览" aria-label="Permalink to “工作流概览”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>需求理解 → 方案设计 → 分步实现 → 测试验证 → 代码审查 → 提交</span></span>\n<span class="line"><span>   │           │           │           │           │         │</span></span>\n<span class="line"><span>   │    Brainstorming   Plan Mode   逐个文件     Claude      /commit</span></span>\n<span class="line"><span>   │       Skill       出计划       编辑执行    运行测试   智能提交</span></span></code></pre></div><h3 id="实战演示" tabindex="-1">实战演示 <a class="header-anchor" href="#实战演示" aria-label="Permalink to “实战演示”">​</a></h3><p><strong>需求</strong>：为用户管理页面添加搜索和筛选功能。</p><p><strong>Step 1：需求分析</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>我想给用户管理页面添加搜索（按用户名/邮箱）和筛选（按角色/状态）功能，</span></span>\n<span class="line"><span>帮我分析一下应该怎么做。</span></span></code></pre></div><p>Claude Code 会自动激活 brainstorming skill，引导你理清需求。</p><p><strong>Step 2：方案设计</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>进入 Plan Mode，设计实现方案。</span></span></code></pre></div><p>Claude 会：</p><ol><li>读取现有的用户管理页面代码</li><li>分析现有的 API 层和组件结构</li><li>提出 2-3 种实现方案</li><li>推荐最优方案并给出理由</li></ol><p><strong>Step 3：分步实现</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>按计划开始实现。</span></span></code></pre></div><p>Claude 会按计划逐步实现：先改 API → 再改组件 → 最后加测试。每一步你都审查变更。</p><p><strong>Step 4：验证</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我运行相关测试，确认功能正常。</span></span></code></pre></div><p><strong>Step 5：提交</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我看看改动，创建合适的提交。</span></span></code></pre></div><h3 id="关键要点" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点" aria-label="Permalink to “关键要点”">​</a></h3><ul><li><strong>永远从 Brainstorming 开始</strong>：一个被充分讨论的需求能减少 80% 的返工</li><li><strong>Plan Mode 是中间层</strong>：在需求和代码之间的方案设计不可跳过</li><li><strong>边做边验</strong>：每完成一个模块就运行测试，不要等到最后</li></ul><h2 id="_5-2-bug-定位与修复流程" tabindex="-1">5.2 Bug 定位与修复流程 <a class="header-anchor" href="#_5-2-bug-定位与修复流程" aria-label="Permalink to “5.2 Bug 定位与修复流程”">​</a></h2><h3 id="工作流概览-1" tabindex="-1">工作流概览 <a class="header-anchor" href="#工作流概览-1" aria-label="Permalink to “工作流概览”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>复现 Bug → 定位根因 → 修复代码 → 添加回归测试 → 验证 → 提交</span></span>\n<span class="line"><span>    │          │           │           │          │       │</span></span>\n<span class="line"><span>  描述现象   Claude      Claude      Claude     运行    /commit</span></span>\n<span class="line"><span>  给 Claude  分析调用链   精准修复    写测试     测试</span></span></code></pre></div><h3 id="实战演示-1" tabindex="-1">实战演示 <a class="header-anchor" href="#实战演示-1" aria-label="Permalink to “实战演示”">​</a></h3><p><strong>Bug 描述</strong>：用户登录后偶尔会跳转到 404 页面。</p><p><strong>Step 1：描述现象</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>用户反馈登录后偶尔被重定向到 404 页面。帮我排查原因。</span></span>\n<span class="line"><span>现象：</span></span>\n<span class="line"><span>- 不是每次都发生</span></span>\n<span class="line"><span>- 似乎是特定用户在特定时间出现</span></span>\n<span class="line"><span>- 生产环境日志显示重定向 URL 中有多余的斜杠</span></span></code></pre></div><p><strong>Step 2：Claude 排查</strong></p><p>Claude Code 会：</p><ol><li>读取登录相关的路由和重定向逻辑</li><li>分析 URL 拼接逻辑，找到 bug 根因</li><li>提出修复方案</li></ol><p><strong>Step 3：修复 + 回归测试</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我修复这个 bug，并添加一个回归测试确保不会复发。</span></span></code></pre></div><p><strong>Step 4：验证修复</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>运行相关测试，并手动确认修复逻辑正确。</span></span></code></pre></div><h3 id="关键要点-1" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点-1" aria-label="Permalink to “关键要点”">​</a></h3><ul><li><strong>给 Claude 尽可能多的信息</strong>：复现步骤、日志、截图、环境信息</li><li><strong>让 Claude 先分析再动手</strong>：&quot;帮我分析原因&quot; 和 &quot;帮我修&quot; 分两步</li><li><strong>始终坚持加回归测试</strong>：这是 Bug 修复的最后一步，也是最容易被跳过的一步</li></ul><h2 id="_5-3-代码审查流程" tabindex="-1">5.3 代码审查流程 <a class="header-anchor" href="#_5-3-代码审查流程" aria-label="Permalink to “5.3 代码审查流程”">​</a></h2><h3 id="工作流概览-2" tabindex="-1">工作流概览 <a class="header-anchor" href="#工作流概览-2" aria-label="Permalink to “工作流概览”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>开发完成 → Claude 预审 → 人工复审 → 修改 → 合并</span></span>\n<span class="line"><span>    │           │            │         │       │</span></span>\n<span class="line"><span>  创建分支    /review     你审查     Claude   merge</span></span>\n<span class="line"><span>            全面扫描     关键逻辑    按要求改</span></span></code></pre></div><h3 id="实战演示-2" tabindex="-1">实战演示 <a class="header-anchor" href="#实战演示-2" aria-label="Permalink to “实战演示”">​</a></h3><p><strong>Step 1：让 Claude 预审</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我审查当前分支的所有变更，重点关注：</span></span>\n<span class="line"><span>- 安全性（SQL 注入、XSS）</span></span>\n<span class="line"><span>- 性能问题</span></span>\n<span class="line"><span>- 异常处理是否完整</span></span></code></pre></div><p>如果你安装了 <code>code-review:code-review</code> Skill，可以直接用：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/code-review:code-review</span></span></code></pre></div><p><strong>Step 2：处理 Claude 的反馈</strong></p><p>当 Claude 提出修改建议时：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>把 Claude 的 review 意见逐条处理：合理的直接修复，不合理的说明原因。</span></span></code></pre></div><h3 id="关键要点-2" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点-2" aria-label="Permalink to “关键要点”">​</a></h3><ul><li><strong>Claude 预审 + 人工复审</strong>：Claude 擅长发现模式问题、安全漏洞、遗漏的边界条件；人类负责业务逻辑正确性和设计一致性</li><li><strong>给出审查重点</strong>：告诉 Claude 你关注什么方面，它的审查更有针对性</li><li><strong>不要盲从</strong>：Claude 的审查意见也可能有误，尤其是业务逻辑相关的</li></ul><h2 id="_5-4-项目重构-迁移流程" tabindex="-1">5.4 项目重构/迁移流程 <a class="header-anchor" href="#_5-4-项目重构-迁移流程" aria-label="Permalink to “5.4 项目重构/迁移流程”">​</a></h2><h3 id="工作流概览-3" tabindex="-1">工作流概览 <a class="header-anchor" href="#工作流概览-3" aria-label="Permalink to “工作流概览”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>评估范围 → 制定迁移计划 → 分模块执行 → 持续验证 → 完成</span></span>\n<span class="line"><span>    │           │             │           │          │</span></span>\n<span class="line"><span>  Claude       Plan         逐个模块    运行测试   /commit</span></span>\n<span class="line"><span>  分析项目      Mode         迁移       确认无回归</span></span></code></pre></div><h3 id="实战演示-3" tabindex="-1">实战演示 <a class="header-anchor" href="#实战演示-3" aria-label="Permalink to “实战演示”">​</a></h3><p><strong>需求</strong>：将项目从 JavaScript 迁移到 TypeScript。</p><p><strong>Step 1：评估</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我分析这个项目迁移到 TypeScript 需要多大工作量，</span></span>\n<span class="line"><span>哪些文件最复杂，建议的迁移顺序是什么。</span></span></code></pre></div><p><strong>Step 2：制定计划</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我制定一个 TypeScript 迁移计划。建议按模块逐步迁移，</span></span>\n<span class="line"><span>先改类型定义和工具函数，再改组件。</span></span></code></pre></div><p><strong>Step 3：分批执行</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>开始迁移 src/utils/ 目录。</span></span></code></pre></div><p>每迁移一个模块，立即运行测试确认无回归。</p><h3 id="关键要点-3" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点-3" aria-label="Permalink to “关键要点”">​</a></h3><ul><li><strong>大型迁移务必用 Plan Mode</strong>：了解全貌再动手</li><li><strong>一次一个模块</strong>：大规模迁移最怕的就是改到一半发现方向错了</li><li><strong>Git 是安全网</strong>：每迁移一个模块就提交一次</li><li><strong>切 Opus 模型</strong>：复杂迁移用最强模型</li></ul><h2 id="_5-5-文档生成与维护" tabindex="-1">5.5 文档生成与维护 <a class="header-anchor" href="#_5-5-文档生成与维护" aria-label="Permalink to “5.5 文档生成与维护”">​</a></h2><h3 id="工作流概览-4" tabindex="-1">工作流概览 <a class="header-anchor" href="#工作流概览-4" aria-label="Permalink to “工作流概览”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>识别文档需求 → 生成初稿 → 人工补充 → 保持更新</span></span>\n<span class="line"><span>      │             │          │          │</span></span>\n<span class="line"><span>    Claude        Claude     你补充    后续修改时</span></span>\n<span class="line"><span>    分析代码      写文档      业务细节   同步更新</span></span></code></pre></div><h3 id="实战演示-4" tabindex="-1">实战演示 <a class="header-anchor" href="#实战演示-4" aria-label="Permalink to “实战演示”">​</a></h3><p><strong>场景 1：生成 API 文档</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我把 src/api/ 下的所有路由生成 API 文档，包括请求参数、返回格式、错误码。</span></span></code></pre></div><p><strong>场景 2：写 README</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>帮我写一个项目 README，包括：项目简介、技术栈、如何启动、目录结构说明。</span></span></code></pre></div><p><strong>场景 3：更新 CLAUDE.md</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>项目最近重构了目录结构，帮我更新 CLAUDE.md。</span></span></code></pre></div><h3 id="关键要点-4" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点-4" aria-label="Permalink to “关键要点”">​</a></h3><ul><li><strong>文档也需审查</strong>：Claude 写的文档可能有不准确的地方，尤其是业务术语</li><li><strong>保持同步</strong>：每次重构后顺带更新文档，不要让文档腐烂</li><li><strong>用 <code>/init</code> 生成 CLAUDE.md 初稿</strong>：然后手动精炼</li></ul>',78))])}]]);export{p as __pageData,h as default};
